#!/bin/bashclearset -erepo="config"if [ "$(uname)" != "Linux" ]; then  echo "this script must be run on linux"  exit 1fiOS=$(grep -Po '(?<=^ID=).*' /etc/os-release | tr -d '"')cd /tmpsudo dnf in -y gitif ! [ -d "/tmp/$repo" ]; then  git clone https://github.com/flawada/$repofiif ! [ -d "/tmp/$repo/blueprints/$OS" ]; then  echo "$OS is not supported yet"  echo "suported distros: "  ls /tmp/$repo/blueprints  exit 1fi#####clearcd /tmp/$repo/blueprints/$OSblueprints=()i=0for blueprint in */; do  blueprints+=("$blueprint")  echo "$i) ${blueprint%/}"  ((i++))doneread -p "select blueprint: " itemcd "${blueprints[$item]}"sudo dnf update -ybash setup.sh